<template>
  <div class="table">
    <div class="crumbs" style="padding: 20px 0 5px 20px">
      <i class="iconfont icon-r-list" style="font-size: 24px">歌单歌曲管理</i>
    </div>

    <div class="container">
      <div class="handle-box">
        <el-input v-model="select_word" placeholder="请输入歌曲名" class="handle-input"></el-input>
        <br /><br />
        <el-button type="danger" style="font-size: 18px" @click="delAll">批量删除</el-button>
        <el-button type="success" style="font-size: 18px" @click="centerDialogVisible = true">添加歌曲</el-button>
      </div>
    </div>

    <el-table
      ref="multipleTable"
      border
      style="width: 100%"
      height="680px"
      :data="data"
      @selection-change="handleSelectionChange"
    >
      <el-table-column type="selection" width="40"></el-table-column>

      <el-table-column label="歌曲图片" width="110" align="center">
        <template slot-scope="scope">
          <div class="song-img">
            <img :src="getUrl(scope.row.pic)" style="width: 100%" />
          </div>
        </template>
      </el-table-column>

      <el-table-column prop="name" label="歌手-歌名" width="160" align="center"></el-table-column>
      <el-table-column prop="introduction" label="专辑" width="160" align="center"></el-table-column>

      <el-table-column label="歌词" align="center">
        <template slot-scope="scope">
          <ul style="height: 100px; overflow: auto">
            <li v-for="(item, index) in parseLyric(scope.row.lyric)" :key="index">
              {{ item }}
            </li>
          </ul>
        </template>
      </el-table-column>

      <el-table-column label="资源更新" align="center" width="180">
        <template slot-scope="scope">
          <el-upload
            :action="uploadPicUrl(scope.row.id)"
            :before-upload="beforeAvatorUpload"
            :on-success="handleAvatorSuccess"
          >
            <el-button>更新图片</el-button>
          </el-upload>
          <br />
          <el-upload
            :action="uploadSongUrl(scope.row.id)"
            :before-upload="beforeSongUpload"
            :on-success="handleSongSuccess"
          >
            <el-button>更新歌曲</el-button>
          </el-upload>
        </template>
      </el-table-column>

      <el-table-column label="操作" width="200" align="center" fixed="right">
        <template slot-scope="scope">
          <el-button type="success" @click="handleEdit(scope.row)" style="font-size: 18px">编辑</el-button>
          <el-button type="danger" @click="handleDelete(scope.row)" style="font-size: 18px">删除</el-button>
        </template>
      </el-table-column>
    </el-table>

    <div class="pagination">
      <el-pagination
        background
        layout="total,prev,pager,next"
        :current-page="currentPage"
        :page-size="pageSize"
        :total="tableData.length"
        @current-change="handleCurrentChange"
      ></el-pagination>
    </div>

    <el-dialog title="添加歌曲" :visible.sync="centerDialogVisible" width="420px" center>
      <el-form :model="registerForm" ref="registerForm" label-width="80px">
        <el-form-item prop="songName" label="歌名" size="mini">
          <el-input v-model="registerForm.songName" placeholder="歌名"></el-input>
        </el-form-item>
        <el-form-item prop="introduction" label="专辑" size="mini">
          <el-input v-model="registerForm.introduction" placeholder="专辑"></el-input>
        </el-form-item>
        <el-form-item prop="lyric" label="歌词" size="mini">
          <el-input v-model="registerForm.lyric" type="textarea" placeholder="歌词"></el-input>
        </el-form-item>
        <el-form-item label="歌曲上传" size="mini">
          <input type="file" @change="onSongFileChange" />
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button size="mini" @click="centerDialogVisible = false">取消</el-button>
        <el-button size="mini" type="primary" @click="addToSongList">确定</el-button>
      </span>
    </el-dialog>

    <el-dialog title="编辑歌曲" :visible.sync="editVisible" width="420px" center>
      <el-form :model="form" ref="form" label-width="80px">
        <el-form-item prop="name" label="歌手-歌名" size="mini">
          <el-input v-model="form.name" placeholder="歌手-歌名"></el-input>
        </el-form-item>
        <el-form-item prop="introduction" label="专辑" size="mini">
          <el-input v-model="form.introduction" placeholder="专辑"></el-input>
        </el-form-item>
        <el-form-item prop="lyric" label="歌词" size="mini">
          <el-input v-model="form.lyric" type="textarea" placeholder="歌词"></el-input>
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button size="mini" @click="editVisible = false">取消</el-button>
        <el-button size="mini" type="primary" @click="editSave">确定</el-button>
      </span>
    </el-dialog>

    <el-dialog title="删除歌曲" :visible.sync="delVisible" width="300px" center>
      <div align="center">删除不可恢复，是否确定删除？</div>
      <span slot="footer">
        <el-button size="mini" @click="delVisible = false">取消</el-button>
        <el-button size="mini" type="primary" @click="deleteRow">确定</el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import { mixin } from "../mixins/index";
import { listSongDetail, listSongAdd, delListSong, songOfName, allSong, updateSong } from "../api/index";

export default {
  mixins: [mixin],
  data() {
    return {
      centerDialogVisible: false,
      editVisible: false,
      delVisible: false,

      songListId: "",
      songListTitle: "",

      registerForm: {
        songName: "",
        introduction: "",
        lyric: ""
      },

      form: {
        id: "",
        name: "",
        introduction: "",
        lyric: ""
      },

      uploadSongFile: null,

      tableData: [],
      tempData: [],
      select_word: "",
      pageSize: 10,
      currentPage: 1,

      idx: -1,
      multipleSelection: []
    };
  },

  computed: {
    data() {
      return this.tableData.slice(
        (this.currentPage - 1) * this.pageSize,
        this.currentPage * this.pageSize
      );
    }
  },

  watch: {
    select_word() {
      if (!this.select_word) {
        this.tableData = this.tempData;
      } else {
        var list = this.tempData || [];
        var kw = this.select_word;
        var out = [];
        for (var i = 0; i < list.length; i++) {
          var item = list[i] || {};
          var name = item.name || "";
          if (name.indexOf(kw) !== -1) out.push(item);
        }
        this.tableData = out;
      }
    }
  },

  created() {
    this.songListId = this.$route.query.id || this.$route.query.songListId || "";
    this.songListTitle = this.$route.query.title || this.$route.query.name || "";

    this.getData();
  },

  methods: {
    resolveSongId(row) {
      if (!row) return "";
      return row.songId || row.song_id || row.songID || row.songid || row.id || "";
    },
    isOk(res) {
      if (res === true || res === 1 || res === "1" || res === "true") return true;
      if (!res) return false;
      if (res.code !== undefined) return Number(res.code) === 1;
      if (res.success !== undefined) return res.success === true || res.success === 1;
      if (res.status !== undefined) return res.status === true || res.status === 1;
      return false;
    },
    handleCurrentChange(val) {
      this.currentPage = val;
    },

    handleSelectionChange(val) {
      this.multipleSelection = val || [];
    },

    delAll() {
      var arr = this.multipleSelection || [];
      if (!arr.length) return this.$message && this.$message.warning("请选择要删除的歌曲");

      var _this = this;
      var count = 0;

      function next(i) {
        if (i >= arr.length) {
          _this.getData();
          _this.$message && _this.$message.success("批量删除完成: " + count);
          return;
        }
        var songId = _this.resolveSongId(arr[i]);
        if (!songId) return next(i + 1);
        delListSong(songId, _this.songListId)
          .then(function (res) {
            if (_this.isOk(res)) count++;
            next(i + 1);
          })
          .catch(function () {
            next(i + 1);
          });
      }
      next(0);
    },

    getData() {
      var _this = this;
      _this.tempData = [];
      _this.tableData = [];

      if (!_this.songListId) {
        _this.currentPage = 1;
        return;
      }

      Promise.all([listSongDetail(_this.songListId), allSong()])
        .then(function ([listRes, songRes]) {
          var arr = [];
          if (Array.isArray(listRes)) arr = listRes;
          else if (listRes && Array.isArray(listRes.data)) arr = listRes.data;
          else if (listRes && listRes.data && Array.isArray(listRes.data.data)) arr = listRes.data.data;
          else if (listRes && listRes.data && Array.isArray(listRes.data.list)) arr = listRes.data.list;
          else if (listRes && Array.isArray(listRes.list)) arr = listRes.list;

          var songs = [];
          if (Array.isArray(songRes)) songs = songRes;
          else if (songRes && Array.isArray(songRes.data)) songs = songRes.data;
          else if (songRes && songRes.data && Array.isArray(songRes.data.data)) songs = songRes.data.data;
          else if (songRes && songRes.data && Array.isArray(songRes.data.list)) songs = songRes.data.list;
          else if (songRes && Array.isArray(songRes.list)) songs = songRes.list;

          var songMap = new Map();
          for (var i = 0; i < songs.length; i++) {
            var s = songs[i];
            if (s && s.id !== undefined && s.id !== null) songMap.set(String(s.id), s);
          }

          var merged = [];
          for (var j = 0; j < arr.length; j++) {
            var item = arr[j] || {};
            var songId = item.songId || item.song_id || item.songID || item.songid || item.id;
            var song = songMap.get(String(songId));
            if (song) merged.push({ ...song, songId: songId });
            else if (item.name) merged.push({ ...item, songId: songId });
          }

          _this.tempData = merged;
          _this.tableData = merged;
          _this.currentPage = 1;

          if (!merged.length && listRes && listRes.code === 0 && listRes.msg) {
            _this.notify && _this.notify(listRes.msg, "error");
          }
        })
        .catch(function (err) {
          console.log(err);
          _this.tempData = [];
          _this.tableData = [];
          _this.currentPage = 1;
        });
    },

    handleDelete(rowOrId) {
      this.idx = this.resolveSongId(rowOrId) || rowOrId;
      this.delVisible = true;
    },

    deleteRow() {
      var _this = this;
      delListSong(this.idx, this.songListId)
        .then(function (res) {
          if (_this.isOk(res)) {
            _this.getData();
            _this.notify && _this.notify("删除成功", "success");
          } else {
            _this.notify && _this.notify("删除失败", "error");
            _this.getData();
          }
        })
        .catch(function (err) {
          console.log(err);
        });

      this.delVisible = false;
    },

    handleEdit(row) {
      this.editVisible = true;
      this.form = {
        id: row.id,
        name: row.name || "",
        introduction: row.introduction || "",
        lyric: row.lyric || ""
      };
    },

    editSave() {
      var params = {
        id: this.form.id,
        name: this.form.name,
        introduction: this.form.introduction,
        lyric: this.form.lyric
      };

      updateSong(params)
        .then((res) => {
          if ((res && res.code == 1) || res === true) {
            this.getData();
            this.notify("修改成功", "success");
          } else {
            this.notify("修改失败", "error");
          }
        })
        .catch((err) => {
          console.log(err);
        });

      this.editVisible = false;
    },

    onSongFileChange(e) {
      var file = e && e.target && e.target.files ? e.target.files[0] : null;
      this.uploadSongFile = file || null;
    },

    addToSongList() {
      var _this = this;
      if (!_this.songListId) return;

      var songName = (_this.registerForm.songName || "").trim();
      if (!songName) {
        return _this.$message && _this.$message.warning("请输入歌名");
      }
      if (!_this.uploadSongFile) {
        return _this.$message && _this.$message.warning("请先选择歌曲文件");
      }

      var form = new FormData();
      form.append("name", songName);
      form.append("introduction", _this.registerForm.introduction || "");
      form.append("lyric", _this.registerForm.lyric || "[00:00:00]暂无歌词");
      form.append("file", _this.uploadSongFile);

      var req = new XMLHttpRequest();
      req.onreadystatechange = function () {
        if (req.readyState == 4 && req.status == 200) {
          try {
            var res = JSON.parse(req.response);
            if ((res && res.code == 1) || res === true) {
              songOfName(songName).then(function (songList) {
                var song = null;
                if (Array.isArray(songList) && songList.length) song = songList[0];

                if (!song || !song.id) {
                  _this.$message && _this.$message.error("未找到歌曲: " + songName);
                  return;
                }

                var params = { songListId: _this.songListId, songId: song.id };
                listSongAdd(params).then(function (res2) {
                  if (res2 && res2.code == 1) {
                    _this.centerDialogVisible = false;
                    _this.registerForm.songName = "";
                    _this.registerForm.introduction = "";
                    _this.registerForm.lyric = "";
                    _this.uploadSongFile = null;
                    _this.getData();
                    _this.notify && _this.notify("添加成功", "success");
                  } else {
                    _this.notify && _this.notify("添加失败", "error");
                  }
                });
              });
            } else {
              _this.$message && _this.$message.error("上传失败");
            }
          } catch (e) {
            _this.$message && _this.$message.error("上传失败");
          }
        }
      };
      req.open("post", _this.$store.state.HOST + "/song/add", true);
      req.send(form);
    },

    parseLyric(text) {
      if (!text) return [];
      var lines = text.split("\n");
      var pattern = /\[\d{2}:\d{2}.(\d{3}|\d{2})\]/g;
      var result = [];
      for (var i = 0; i < lines.length; i++) {
        result.push(lines[i].replace(pattern, ""));
      }
      return result;
    },

    uploadPicUrl(id) {
      return this.$store.state.HOST + "/song/updateSongPic?id=" + id;
    },

    uploadSongUrl(id) {
      return this.$store.state.HOST + "/song/updateSongUrl?id=" + id;
    },

    beforeSongUpload(file) {
      var testMsg = file.name.substring(file.name.lastIndexOf(".") + 1);
      if (testMsg != "mp3") {
        this.$message({ message: "上传文件只能是 mp3 格式", type: "error" });
        return false;
      }
      return true;
    },

    handleSongSuccess(res) {
      if ((res && res.code == 1) || res === true) {
        this.getData();
        this.$notify({ title: "上传成功", type: "success" });
      } else {
        this.$notify({ title: "上传失败", type: "error" });
      }
    }
  }
};
</script>

<style scoped>
.handle-box {
  margin-bottom: 20px;
}
.song-img {
  width: 100%;
  height: 80px;
  border-radius: 5px;
  margin-bottom: 5px;
  overflow: hidden;
}
.handle-input {
  width: 300px;
  display: inline-block;
}
.pagination {
  display: flex;
  justify-content: center;
}
</style>




